#include <bits/stdc++.h>
using namespace std;
int n,dp_max[202][202],dp_min[202][202],m[202],s[202];
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>m[i];
        m[i+n]=m[i];
    }
    for(int i=1;i<=n*2;i++){
        s[i]=s[i-1]+m[i];
        //dp_max[i][i]=dp_min[i][i]=0;
        if(i>1)dp_max[i-1][i]=dp_min[i-1][i]=m[i-1]+m[i];
    }
    for(int i=3;i<=2*n;i++){
        for(int j=1;j+i-1<=2*n;j++){
            int e=j+i-1;
            dp_min[j][e]=1<<31-1,dp_max[j][e]=0;
            for(int k=j;k<e;k++){
                dp_min[j][e]=min(dp_min[j][e],s[e]-s[j-1]+dp_min[j][k]+dp_min[k+1][e]);
                dp_max[j][e]=max(dp_max[j][e],s[e]-s[j-1]+dp_max[j][k]+dp_max[k+1][e]);
            }
        }
    }
    int ans_max=0,ans_min=1<<31-1;
    for(int i=1;i<=n;i++)ans_max=max(ans_max,dp_max[i][i+n-1]),ans_min=min(ans_min,dp_min[i][i+n-1]);
    cout<<ans_min<<'\n'<<ans_max;
    return 0;
}
